item.overviewText:
@@preprocessing
<%_
;(() => {
  const __mh = getMessageVar('stat_data', { defaults: {} }) || {};
  const __mhB = _.get(__mh, 'Chiến_đấu.Đang_chiến_đấu', false) === true;
  const __mhH = _.get(__mh, 'Sự_kiện_hiện_tại.Săn_quái_vật', {});
  const __mhHas = __mhH && Object.keys(__mhH).length > 0;
  const __mhA = String(_.get(__mh, 'Thông_tin_thế_giới.Vị_trí.Khu_vực', '') || '') + String(_.get(__mh, 'Thông_tin_thế_giới.Vị_trí.Địa_điểm', '') || '');
  var __mhT = __mhA.includes('thành') || __mhA.includes('cảng') || __mhA.includes('chợ') || __mhA.includes('quảng trường') || __mhA.includes('phố') || __mhA.includes('ngõ') || __mhA.includes('quán') || __mhA.includes('tập thị') || __mhA.includes('doanh') || __mhA.includes('cứ điểm') || __mhA.includes('tiền trạm') || __mhA.includes('hiệp hội') || __mhA.includes('Kết Giới Ngọc') || __mhA.includes('bộ lạc') || __mhA.includes('tửu quán') || __mhA.includes('công xưởng') || __mhA.includes('cửa hàng') || __mhA.includes('thợ rèn') || __mhA.includes('công hội') || __mhA.includes('luyện kim') || __mhA.includes('trạm') || __mhA.includes('làng');
_%>
<%_ if (__mhB || __mhHas) { _%>
MH_săn_bắt_chiến_đấu_kích_hoạt
<%_ } _%>
<%_ if (!__mhB && !__mhHas && !__mhT) { _%>
MH_săn_bắt_gặp_gỡ_kích_hoạt
<%_ } _%>
<%_ if (!__mhB && __mhT) { _%>
MH_săn_bắt_cửa_hàng_kích_hoạt
<%_ } _%>
<%_
})();
_%>
(IMPORTANT: giao thức chuyển cảnh cao hơn tất cả, bắt buộc tuân thủ.)

